create table dirkspzm32.isi_mail_queue (
    mail_id         number(8, 0) not null enable,
    created_date    date default sysdate,
    send_status     varchar2(1 char) default 'N',
    mail_address    varchar2(200 char),
    betreff_text    varchar2(150 char),
    inhalt_text     varchar2(2000 char),
    send_modul      varchar2(100 char) not null enable,
    send_error_text varchar2(300 char) default '',
    send_date       date default sysdate,
    retry_count     number default 0 not null enable
);

alter table dirkspzm32.isi_mail_queue
    add constraint pk_mail_id primary key ( mail_id )
        using index enable;


